PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE locations (   id TEXT PRIMARY KEY,   name TEXT NOT NULL,   code TEXT NOT NULL );
CREATE TABLE categories (   id TEXT PRIMARY KEY,   name TEXT NOT NULL );
CREATE TABLE employees (   id TEXT PRIMARY KEY,   email TEXT NOT NULL,   role TEXT DEFAULT 'USER',   locationId TEXT,   status TEXT NOT NULL,   FOREIGN KEY(locationId) REFERENCES locations(id) );
CREATE TABLE assets (   id TEXT PRIMARY KEY,   assetTag TEXT NOT NULL,   categoryId TEXT,   parentAssetId TEXT,   locationId TEXT,   assignedTo TEXT,   status TEXT NOT NULL,   imageR2Key TEXT, purchasePrice REAL, currentBookValue REAL, purchaseDate TEXT,   FOREIGN KEY(categoryId) REFERENCES categories(id),   FOREIGN KEY(locationId) REFERENCES locations(id),   FOREIGN KEY(assignedTo) REFERENCES employees(id),   FOREIGN KEY(parentAssetId) REFERENCES assets(id) );
CREATE TABLE audit_logs (   id TEXT PRIMARY KEY,   assetId TEXT NOT NULL,   action TEXT NOT NULL,   actorId TEXT NOT NULL,   locationId TEXT,   detailsJson TEXT,   createdAt TEXT NOT NULL,   FOREIGN KEY(assetId) REFERENCES assets(id),   FOREIGN KEY(locationId) REFERENCES locations(id) );
CREATE TABLE depreciation_logs (   id TEXT PRIMARY KEY,   assetId TEXT NOT NULL,   period TEXT NOT NULL,   depreciationAmount REAL NOT NULL,   bookValueAfter REAL NOT NULL,   calculatedAt TEXT NOT NULL,   FOREIGN KEY(assetId) REFERENCES assets(id) );
